// Pull both ensures-`forall|i|` about page_array into the local proof
// context so their triggers fire on common `page_array@[i]` terms.
assert(forall|i: int|
    #![trigger post1_self_.page_array@[i]]
    #![trigger pre_self_.page_array@[i]]
    0 <= i < NUM_PAGES && i != index ==> post1_self_.page_array@[i] =~= pre_self_.page_array@[i]);
assert(forall|i: int|
    #![trigger post2_self_.page_array@[i]]
    #![trigger pre_self_.page_array@[i]]
    0 <= i < NUM_PAGES && i != index ==> post2_self_.page_array@[i] =~= pre_self_.page_array@[i]);

// At `index`, every field of both post-states equals the corresponding
// pre-state field (or `ref_count`), so the two `Page` values agree
// structurally via field-wise `=~=` chained through `pre_self_`.
assert(post1_self_.page_array@[index as int] =~= post2_self_.page_array@[index as int]);

// Pointwise: at every i in [0, NUM_PAGES) the two page arrays agree.
assert forall|i: int| 0 <= i < NUM_PAGES implies
    post1_self_.page_array@[i] =~= post2_self_.page_array@[i] by {
    if i == index as int {
        // Handled by the assertion above.
    } else {
        // Both equal pre_self_.page_array@[i] by the two `forall` assertions.
    }
}

// Sequence extensionality lifts pointwise equality to view equality.
assert(post1_self_.page_array@ =~= post2_self_.page_array@);
